        // Check if dark mode is enabled via cookie preference
        var darkModeEnabled = false;

        // Check cookie preference first (user override)
        var cookieValue = getCookie('dark_mode_enabled');
        if (cookieValue === 'true') {
          darkModeEnabled = true;
        } else if (cookieValue === 'false') {
          darkModeEnabled = false;
        } else {
          // If no cookie preference, default to disabled (user can toggle it on)
          darkModeEnabled = false;
        }

        // Apply dark mode immediately if enabled
        if (darkModeEnabled) {
          document.documentElement.classList.add('dark-mode');
          // Also add to body when it exists (for immediate effect)
          if (document.body) {
            document.body.classList.add('dark-mode');
          } else {
            // If body doesn't exist yet, wait for it
            var observer = new MutationObserver(function(mutations) {
              if (document.body) {
                document.body.classList.add('dark-mode');
                observer.disconnect();
              }
            });
            observer.observe(document.documentElement, { childList: true });
          }
        }
      })();
    </script>
